function maxSumRangeQuery(nums, requests) {
    const n = nums.length;
    const cnt = new Array(n).fill(0);
    const mod = 1e9 + 7;

    for (const req of requests) {
        cnt[req[0]]++;
        if (req[1] + 1 < n) cnt[req[1] + 1]--;
    }

    for (let i = 1; i < n; i++) {
        cnt[i] += cnt[i - 1];
    }

    nums.sort((a, b) => a - b);
    cnt.sort((a, b) => a - b);

    let ans = 0;
    for (let i = 0; i < n; i++) {
        ans += (BigInt(nums[i]) * BigInt(cnt[i])) % mod;
    }

    return Number(ans % mod);
}
```

    1. Initialize an array `cnt` of the same length as `nums` and set all elements to 0.
2. For each request `[starti, endi]`, increment `cnt[starti]` and decrement `cnt[endi + 1]` if `endi + 1` is within the bounds of the array.
3. For each successive element in `cnt` starting from index 1, add the element at the previous index to it, thereby obtaining the prefix sum of the `cnt` array.
4. Sort both `nums` and `cnt` in ascending order.
5. Compute the sum by multiplying each element in `nums` with the corresponding element in `cnt`. Because the multiplication may cause overflow, this operation modulo 1e9 + 7 is taken.
6. Return the total sum modulo 1e9 + 7.

